import React from "react"
import Select from 'react-select'
//import Calendar from 'react-select-date'
import { Calendar, DateObject } from "react-multi-date-picker"
import { properties } from '../../properties/properties.js'
import Moment from 'moment'
import {Tab, Tabs, TabList, TabPanel} from 'react-tabs'
import 'react-tabs/style/react-tabs.css'


class EvalStatus extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0
        };
    }




        componentDidMount() {


            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            var backUrl = properties.backend + `evalstatus`

            fetch(backUrl, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                this.setState({results: response})
                this.setState({screen: 1})

              })
              .catch(err => {
                console.log(err);
              });

        }




          render() {


            var header = "Loading ..."


            if (this.state.screen === 1) {
              header = ""
              var content = []

              console.log(this.state.results.complete)
              console.log(this.state.results.error)
              console.log(this.state.results.incomplete)


              var paddingSize = "8px"
              var i = 0

                var incomplete = []
                incomplete.push(<tr><td style={{padding: paddingSize}}>Issued</td><td style={{padding: paddingSize}}>Recipient</td><td style={{padding: paddingSize}}>Evaluation</td><td style={{padding: paddingSize}}>Rotation</td><td style={{padding: paddingSize}}>Status</td></tr>)
                this.state.results.incomplete.map(rec => {
                        var bgcolor = "#FAFAFA"
                        if (i%2 == 0) {
                            bgcolor = "#F4F4F4"
                        }
                        incomplete.push(<tr style={{backgroundColor: bgcolor}}><td style={{padding: paddingSize}}>{rec.date}</td><td style={{padding: paddingSize}}>{rec.evaluator}</td><td style={{padding: paddingSize}}>{rec.title}</td><td style={{padding: paddingSize}}>{Moment(rec.rotationStart).format("MM/DD") + "-" + Moment(rec.rotationEnd).format("MM/DD") }</td><td style={{padding: paddingSize}}>{rec.status.status_title}</td></tr>)
                        i += 1
                    }
                )


                i = 0

                var complete = []
                complete.push(<tr><td style={{padding: paddingSize}}>Issued</td><td style={{padding: paddingSize}}>Recipient</td><td style={{padding: paddingSize}}>Evaluation</td><td style={{padding: paddingSize}}>Rotation</td><td style={{padding: paddingSize}}>Status</td></tr>)
                this.state.results.complete.map(rec => {
                        var bgcolor = "#FAFAFA"
                        if (i%2 == 0) {
                            bgcolor = "#F4F4F4"
                        }
                        complete.push(<tr style={{backgroundColor: bgcolor}}><td style={{padding: paddingSize}}>{rec.date}</td><td style={{padding: paddingSize}}>{rec.evaluator}</td><td style={{padding: paddingSize}}>{rec.title}</td><td style={{padding: paddingSize}}>{Moment(rec.rotationStart).format("MM/DD") + "-" + Moment(rec.rotationEnd).format("MM/DD") }</td><td style={{padding: paddingSize}}>{rec.status.status_title}</td></tr>)
                        i += 1
                    }
                )

                i = 0

                var error = []
                error.push(<tr><td style={{padding: paddingSize}}>Issued</td><td style={{padding: paddingSize}}>Recipient</td><td style={{padding: paddingSize}}>Evaluation</td><td style={{padding: paddingSize}}>Rotation</td><td style={{padding: paddingSize}}>Status</td></tr>)
                this.state.results.error.map(rec => {
                        var bgcolor = "#FAFAFA"
                        if (i%2 == 0) {
                            bgcolor = "#F4F4F4"
                        }
                        error.push(<tr style={{backgroundColor: bgcolor}}><td style={{padding: paddingSize}}>{rec.date}</td><td style={{padding: paddingSize}}>{rec.evaluator}</td><td style={{padding: paddingSize}}>{rec.title}</td><td style={{padding: paddingSize}}>{Moment(rec.rotationStart).format("MM/DD") + "-" + Moment(rec.rotationEnd).format("MM/DD") }</td><td style={{padding: paddingSize}}>{rec.status.status_title}</td></tr>)
                        i += 1
                    }
                )


              content.push(<Tabs>
                <TabList>
                    <Tab>Incomplete</Tab>
                    <Tab>Complete</Tab>
                    <Tab>Error</Tab>
                </TabList>
                <TabPanel><div >
                    <table>{incomplete}</table>
                    </div></TabPanel>
                <TabPanel><div >   <table>{complete}</table></div></TabPanel>
                <TabPanel><div > <table>{error}</table></div></TabPanel>
            </Tabs>)

            }



            return (
                <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default EvalStatus
